/**
 * Verifies profiles/bookmarks tables, columns, and basic RLS behavior.
 * Run after applying db/schema.sql in the Supabase SQL Editor:
 *   node db/verify-schema.mjs
 */

import { createClient } from "@supabase/supabase-js";
import { readFileSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const envPath = resolve(__dirname, "../.env.local");
const env = readFileSync(envPath, "utf8");
const get = (key) => env.match(new RegExp(`^${key}=(.+)$`, "m"))?.[1]?.trim();

const url = get("NEXT_PUBLIC_SUPABASE_URL");
const anonKey = get("NEXT_PUBLIC_SUPABASE_ANON_KEY");
const serviceKey = get("SUPABASE_SERVICE_ROLE_KEY");

if (!url || !anonKey || !serviceKey) {
  console.error("Missing Supabase env vars in .env.local");
  process.exit(1);
}

const admin = createClient(url, serviceKey);
const anon = createClient(url, anonKey);

let passed = 0;
let failed = 0;

function check(name, ok, detail = "") {
  if (ok) {
    passed++;
    console.log(`✓ ${name}${detail ? ` — ${detail}` : ""}`);
  } else {
    failed++;
    console.error(`✗ ${name}${detail ? ` — ${detail}` : ""}`);
  }
}

const profileCols = await admin
  .from("profiles")
  .select("id, handle, created_at")
  .limit(1);
check(
  "profiles table + columns",
  !profileCols.error,
  profileCols.error?.message,
);

const bookmarkCols = await admin
  .from("bookmarks")
  .select("id, user_id, title, url, is_public, created_at")
  .limit(1);
check(
  "bookmarks table + columns",
  !bookmarkCols.error,
  bookmarkCols.error?.message,
);

const anonProfiles = await anon.from("profiles").select("id").limit(1);
check(
  "RLS: anon can read profiles",
  !anonProfiles.error,
  anonProfiles.error?.message,
);

const anonBookmarks = await anon.from("bookmarks").select("id").limit(1);
check(
  "RLS: anon can query bookmarks",
  !anonBookmarks.error,
  anonBookmarks.error?.message,
);

const badHandle = await admin.from("profiles").insert({
  id: "00000000-0000-0000-0000-000000000099",
  handle: "AB",
});
check(
  "handle_format check constraint",
  !!badHandle.error,
  badHandle.error?.message ?? "expected rejection",
);

console.log(`\n${passed} passed, ${failed} failed`);
process.exit(failed > 0 ? 1 : 0);

export type Bookmark = {
  id: string;
  user_id: string;
  title: string;
  url: string;
  is_public: boolean;
  created_at: string;
};

export type Profile = {
  id: string;
  handle: string;
  created_at: string;
};

