import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { resend } from "@/lib/resend/client";
import { welcomeEmailHtml } from "@/lib/resend/templates/welcome";
import {
  buildConfirmationUrl,
  deleteUserByEmail,
  findUserByEmail,
} from "@/lib/auth/users";

const HANDLE_PATTERN = /^[a-z0-9_]{3,30}$/;

export async function POST(request: Request) {
  let body: { email?: string; password?: string; handle?: string };

  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request body" }, { status: 400 });
  }

  const email = body.email?.trim();
  const password = body.password;
  const handle = body.handle?.trim().toLowerCase();

  if (!email || !password || !handle) {
    return NextResponse.json(
      { error: "email, password, and handle are required" },
      { status: 400 },
    );
  }

  if (password.length < 8) {
    return NextResponse.json(
      { error: "Password must be at least 8 characters" },
      { status: 400 },
    );
  }

  if (!HANDLE_PATTERN.test(handle)) {
    return NextResponse.json(
      {
        error:
          "Handle must be 3–30 characters: lowercase letters, numbers, and underscores only",
      },
      { status: 400 },
    );
  }

  const admin = createAdminClient();

  const { data: existingHandle } = await admin
    .from("profiles")
    .select("id")
    .eq("handle", handle)
    .maybeSingle();

  const existingUser = await findUserByEmail(email);

  if (existingUser?.email_confirmed_at) {
    return NextResponse.json({ error: "Email already in use" }, { status: 409 });
  }

  if (existingUser && !existingUser.email_confirmed_at) {
    await deleteUserByEmail(email);
  } else if (existingHandle && existingHandle.id !== existingUser?.id) {
    return NextResponse.json({ error: "handle already taken" }, { status: 409 });
  }

  const { data: createdUser, error: createError } =
    await admin.auth.admin.createUser({
      email,
      password,
      email_confirm: false,
      user_metadata: { handle },
    });

  if (createError) {
    const message = createError.message.toLowerCase();

    if (
      message.includes("already registered") ||
      message.includes("already exists") ||
      message.includes("duplicate")
    ) {
      return NextResponse.json({ error: "Email already in use" }, { status: 409 });
    }

    if (message.includes("rate limit")) {
      return NextResponse.json(
        {
          error:
            "Too many signup attempts. Please wait a few minutes before trying again.",
        },
        { status: 429 },
      );
    }

    console.error("signup createUser error:", createError);
    return NextResponse.json({ error: "Failed to create account" }, { status: 500 });
  }

  const userId = createdUser.user?.id;

  if (!userId) {
    return NextResponse.json({ error: "Failed to create account" }, { status: 500 });
  }

  const { error: profileError } = await admin.from("profiles").insert({
    id: userId,
    handle,
  });

  if (profileError) {
    await admin.auth.admin.deleteUser(userId);

    if (profileError.code === "23505") {
      return NextResponse.json({ error: "handle already taken" }, { status: 409 });
    }

    console.error("signup profile insert error:", profileError);
    return NextResponse.json({ error: "Failed to create profile" }, { status: 500 });
  }

  const confirmUrl = await buildConfirmationUrl(email, password);

  const { error: emailError } = await resend.emails.send({
    from: "Bookmarks <onboarding@resend.dev>",
    to: email,
    subject: `Welcome to Bookmarks, @${handle}`,
    html: welcomeEmailHtml(handle, confirmUrl),
  });

  if (emailError) {
    console.error("signup welcome email error:", emailError);

    if (emailError.message?.toLowerCase().includes("rate limit")) {
      return NextResponse.json(
        {
          error:
            "Account created but email could not be sent. Use resend confirmation on the next page.",
        },
        { status: 429 },
      );
    }
  }

  return NextResponse.json({ success: true }, { status: 201 });
}

"use client";

import Link from "next/link";
import { useState, type FormEvent } from "react";

export default function ResendConfirmationForm() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setMessage(null);
    setError(null);
    setLoading(true);

    try {
      const response = await fetch("/api/auth/resend-confirmation", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email: email.trim(), password }),
      });

      const data = await response.json().catch(() => ({}));

      if (!response.ok) {
        setError(data.error ?? "Failed to resend confirmation email.");
        return;
      }

      setMessage("Confirmation email sent. Check your inbox and click the button.");
    } catch {
      setError("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="mt-8 border-t border-gray-200 pt-6 text-left">
      <h2 className="mb-2 text-sm font-semibold text-gray-900">
        Didn&apos;t get the email?
      </h2>
      <p className="mb-4 text-sm text-gray-600">
        Enter the same email and password you used to sign up. On Resend free tier,
        emails can only be sent to your verified address.
      </p>

      <form onSubmit={handleSubmit} className="flex flex-col gap-3">
        <input
          type="email"
          required
          placeholder="Email"
          value={email}
          onChange={(event) => setEmail(event.target.value)}
          className="w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        <input
          type="password"
          required
          minLength={8}
          placeholder="Password"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
          className="w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        <button
          type="submit"
          disabled={loading}
          className="rounded-md border border-gray-300 bg-white px-4 py-2 text-sm font-medium text-gray-900 hover:bg-gray-50 disabled:opacity-60"
        >
          {loading ? "Sending..." : "Resend confirmation email"}
        </button>
      </form>

      {message && <p className="mt-3 text-sm text-green-700">{message}</p>}
      {error && <p className="mt-3 text-sm text-red-600">{error}</p>}
    </div>
  );
}

