"use client";

import { useEffect, type ReactNode } from "react";

type ModalProps = {
  open: boolean;
  onClose: () => void;
  title: string;
  children: ReactNode;
};

export default function Modal({ open, onClose, title, children }: ModalProps) {
  useEffect(() => {
    if (!open) {
      return;
    }

    function handleKeyDown(event: KeyboardEvent) {
      if (event.key === "Escape") {
        onClose();
      }
    }

    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [open, onClose]);

  if (!open) {
    return null;
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <button
        type="button"
        aria-label="Close modal"
        className="absolute inset-0 bg-black/40"
        onClick={onClose}
      />
      <div className="relative z-10 w-full max-w-md rounded-lg border border-gray-200 bg-white p-6 shadow-lg">
        <div className="mb-4 flex items-center justify-between">
          <h2 className="text-lg font-semibold text-gray-900">{title}</h2>
          <button
            type="button"
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600"
            aria-label="Close"
          >
            ✕
          </button>
        </div>
        {children}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, type FormEvent } from "react";
import type { Bookmark } from "@/lib/types";
import Modal from "@/components/ui/Modal";

type BookmarkFormProps = {
  open: boolean;
  onClose: () => void;
  bookmark?: Bookmark | null;
  onSuccess: (bookmark: Bookmark) => void;
};

export default function BookmarkForm({
  open,
  onClose,
  bookmark,
  onSuccess,
}: BookmarkFormProps) {
  const isEditing = Boolean(bookmark);
  const [title, setTitle] = useState("");
  const [url, setUrl] = useState("");
  const [isPublic, setIsPublic] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (open) {
      setTitle(bookmark?.title ?? "");
      setUrl(bookmark?.url ?? "");
      setIsPublic(bookmark?.is_public ?? false);
      setError(null);
    }
  }, [open, bookmark]);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setError(null);
    setLoading(true);

    try {
      const payload = { title: title.trim(), url: url.trim(), is_public: isPublic };
      const response = await fetch(
        isEditing ? `/api/bookmarks/${bookmark!.id}` : "/api/bookmarks",
        {
          method: isEditing ? "PUT" : "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        },
      );

      const data = await response.json().catch(() => ({}));

      if (!response.ok) {
        setError(data.error ?? "Failed to save bookmark");
        return;
      }

      onSuccess(data as Bookmark);
      onClose();
    } catch {
      setError("Failed to save bookmark");
    } finally {
      setLoading(false);
    }
  }

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={isEditing ? "Edit bookmark" : "New bookmark"}
    >
      <form onSubmit={handleSubmit} className="flex flex-col gap-4 text-gray-900">
        <div>
          <label htmlFor="bookmark-title" className="mb-1 block text-sm font-medium">
            Title
          </label>
          <input
            id="bookmark-title"
            type="text"
            required
            maxLength={200}
            value={title}
            onChange={(event) => setTitle(event.target.value)}
            className="w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-gray-900 focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        <div>
          <label htmlFor="bookmark-url" className="mb-1 block text-sm font-medium">
            URL
          </label>
          <input
            id="bookmark-url"
            type="url"
            required
            placeholder="https://"
            value={url}
            onChange={(event) => setUrl(event.target.value)}
            className="w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-gray-900 focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        <label className="flex cursor-pointer items-center gap-2 text-sm text-gray-700">
          <input
            type="checkbox"
            checked={isPublic}
            onChange={(event) => setIsPublic(event.target.checked)}
            className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
          />
          Public — anyone can see this
        </label>

        {error && <p className="text-sm text-red-600">{error}</p>}

        <div className="flex justify-end gap-2">
          <button
            type="button"
            onClick={onClose}
            className="rounded-md border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 disabled:opacity-60"
          >
            {loading ? "Saving..." : isEditing ? "Save changes" : "Add bookmark"}
          </button>
        </div>
      </form>
    </Modal>
  );
}

"use client";

import type { Bookmark } from "@/lib/types";

type BookmarkCardProps = {
  bookmark: Bookmark;
  onEdit: (bookmark: Bookmark) => void;
  onDelete: (id: string) => void;
};

function truncateUrl(url: string, maxLength = 50) {
  if (url.length <= maxLength) {
    return url;
  }

  return `${url.slice(0, maxLength)}…`;
}

export default function BookmarkCard({
  bookmark,
  onEdit,
  onDelete,
}: BookmarkCardProps) {
  function handleDelete() {
    if (!confirm("Delete this bookmark?")) {
      return;
    }

    onDelete(bookmark.id);
  }

  return (
    <article className="rounded-lg border border-gray-200 bg-white p-4 shadow-sm">
      <div className="flex items-start justify-between gap-4">
        <div className="min-w-0 flex-1">
          <a
            href={bookmark.url}
            target="_blank"
            rel="noopener noreferrer"
            className="block truncate font-medium text-blue-600 hover:underline"
          >
            {bookmark.title}
          </a>
          <p className="mt-1 truncate text-sm text-gray-500">
            {truncateUrl(bookmark.url)}
          </p>
          <span
            className={`mt-2 inline-block rounded-full px-2 py-0.5 text-xs font-medium ${
              bookmark.is_public
                ? "bg-green-100 text-green-800"
                : "bg-gray-100 text-gray-600"
            }`}
          >
            {bookmark.is_public ? "Public" : "Private"}
          </span>
        </div>

        <div className="flex shrink-0 gap-2">
          <button
            type="button"
            onClick={() => onEdit(bookmark)}
            className="rounded-md border border-gray-300 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50"
          >
            Edit
          </button>
          <button
            type="button"
            onClick={handleDelete}
            className="rounded-md border border-red-200 px-3 py-1.5 text-sm font-medium text-red-600 hover:bg-red-50"
          >
            Delete
          </button>
        </div>
      </div>
    </article>
  );
}

"use client";

import { useState } from "react";
import type { Bookmark } from "@/lib/types";
import BookmarkCard from "@/components/bookmarks/BookmarkCard";
import BookmarkForm from "@/components/bookmarks/BookmarkForm";

type BookmarkListProps = {
  initialBookmarks: Bookmark[];
};

export default function BookmarkList({ initialBookmarks }: BookmarkListProps) {
  const [bookmarks, setBookmarks] = useState(initialBookmarks);
  const [formOpen, setFormOpen] = useState(false);
  const [editingBookmark, setEditingBookmark] = useState<Bookmark | null>(null);

  function openCreateForm() {
    setEditingBookmark(null);
    setFormOpen(true);
  }

  function openEditForm(bookmark: Bookmark) {
    setEditingBookmark(bookmark);
    setFormOpen(true);
  }

  function closeForm() {
    setFormOpen(false);
    setEditingBookmark(null);
  }

  function handleSuccess(bookmark: Bookmark) {
    setBookmarks((current) => {
      const existingIndex = current.findIndex((item) => item.id === bookmark.id);

      if (existingIndex >= 0) {
        const updated = [...current];
        updated[existingIndex] = bookmark;
        return updated;
      }

      return [bookmark, ...current];
    });
  }

  async function handleDelete(id: string) {
    const previous = bookmarks;
    setBookmarks((current) => current.filter((item) => item.id !== id));

    try {
      const response = await fetch(`/api/bookmarks/${id}`, { method: "DELETE" });

      if (!response.ok) {
        setBookmarks(previous);
      }
    } catch {
      setBookmarks(previous);
    }
  }

  return (
    <>
      <div className="mb-4 flex justify-end">
        <button
          type="button"
          onClick={openCreateForm}
          className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700"
        >
          New Bookmark
        </button>
      </div>

      {bookmarks.length === 0 ? (
        <p className="rounded-lg border border-dashed border-gray-300 bg-white py-12 text-center text-gray-500 shadow-sm">
          No bookmarks yet. Add your first one.
        </p>
      ) : (
        <ul className="flex flex-col gap-3">
          {bookmarks.map((bookmark) => (
            <li key={bookmark.id}>
              <BookmarkCard
                bookmark={bookmark}
                onEdit={openEditForm}
                onDelete={handleDelete}
              />
            </li>
          ))}
        </ul>
      )}

      <BookmarkForm
        open={formOpen}
        onClose={closeForm}
        bookmark={editingBookmark}
        onSuccess={handleSuccess}
      />
    </>
  );
}

